{"file_path": "/home/eren/Documents/task4/Meridian_Academy/repo/backend/src/routes/auth.rs", "content": "use crate::middleware::AuthenticatedUser;
use crate::models::auth::{ChangePasswordRequest, Claims, LoginRequest, LoginResponse};
use crate::models::user::{CreateUserRequest, UserResponse};
use crate::DbPool;
use bcrypt::{hash, verify, DEFAULT_COST};
use chrono::Utc;
use jsonwebtoken::{encode, EncodingKey, Header};
use rocket::http::Status;
use rocket::serde::json::Json;
use rocket::State;
use uuid::Uuid;

fn generate_token(user_id: &str, email: &str, role: &str) -> Result<String, Status> {
    let jwt_secret =
        std::env::var("JWT_SECRET").unwrap_or_else(|_| "default_dev_secret_change_me".into());
    let expiry_hours: u64 = std::env::var("TOKEN_EXPIRY_HOURS")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(24);

    let now = Utc::now().timestamp() as usize;
    let claims = Claims {
        sub: user_id.to_string(),
        email: email.to_string(),
        role: role.to_string(),
        iat: now,
        exp: now + (expiry_hours as usize * 3600),
    };

    encode(
        &Header::default(),
        &claims,
        &EncodingKey::from_secret(jwt_secret.as_bytes()),
    )
    .map_err(|_| Status::InternalServerError)
}

#[post("/login", data = "<req>")]
pub async fn login(
    pool: &State<DbPool>,
    req: Json<LoginRequest>,
) -> Result<Json<LoginResponse>, Status> {
    let row = sqlx::query_as::<_, (String, String, String, String, String, bool)>(
        "SELECT id, email, password_hash, first_name, last_name, role FROM users WHERE email = ? AND is_active = true"
    )
    .bind(&req.email)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match row {
        Some((id, email, password_hash, first_name, last_name, role)) => {
            if !verify(&req.password, &password_hash).unwrap_or(false) {
                // Log failed attempt
                let _ = sqlx::query(
                    "INSERT INTO audit_log (id, user_id, action, details, created_at) VALUES (?, ?, 'login_failed', 'Invalid password', NOW())"
                )
                .bind(Uuid::new_v4().to_string())
                .bind(&id)
                .execute(pool.inner())
                .await;
                return Err(Status::Unauthorized);
            }

            let token = generate_token(&id, &email, &role)?;

            // Log successful login
            let _ = sqlx::query(
                "INSERT INTO audit_log (id, user_id, action, details, created_at) VALUES (?, ?, 'login_success', 'User logged in', NOW())"
            )
            .bind(Uuid::new_v4().to_string())
            .bind(&id)
            .execute(pool.inner())
            .await;

            Ok(Json(LoginResponse {
                token,
                user: UserResponse {
                    id,
                    email,
                    first_name,
                    last_name,
                    role,
                    is_active: true,
                    created_at: None,
                },
            }))
        }
        None => Err(Status::Unauthorized),
    }
}

#[post("/register", data = "<req>")]
pub async fn register(
    pool: &State<DbPool>,
    req: Json<CreateUserRequest>,
) -> Result<Json<LoginResponse>, Status> {
    // Check if email already exists
    let existing = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM users WHERE email = ?")
        .bind(&req.email)
        .fetch_one(pool.inner())
        .await
        .map_err(|_| Status::InternalServerError)?;

    if existing > 0 {
        return Err(Status::Conflict);
    }

    // Validate role
    let valid_roles = ["student", "instructor", "academic_staff", "administrator"];
    if !valid_roles.contains(&req.role.as_str()) {
        return Err(Status::BadRequest);
    }

    let id = Uuid::new_v4().to_string();
    let password_hash = hash(&req.password, DEFAULT_COST).map_err(|_| Status::InternalServerError)?;

    sqlx::query(
        "INSERT INTO users (id, email, password_hash, first_name, last_name, role, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, true, NOW(), NOW())"
    )
    .bind(&id)
    .bind(&req.email)
    .bind(&password_hash)
    .bind(&req.first_name)
    .bind(&req.last_name)
    .bind(&req.role)
    .execute(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    let token = generate_token(&id, &req.email, &req.role)?;

    // Audit log
    let _ = sqlx::query(
        "INSERT INTO audit_log (id, user_id, action, details, created_at) VALUES (?, ?, 'user_registered', 'New user registration', NOW())"
    )
    .bind(Uuid::new_v4().to_string())
    .bind(&id)
    .execute(pool.inner())
    .await;

    Ok(Json(LoginResponse {
        token,
        user: UserResponse {
            id,
            email: req.email.clone(),
            first_name: req.first_name.clone(),
            last_name: req.last_name.clone(),
            role: req.role.clone(),
            is_active: true,
            created_at: None,
        },
    }))
}

#[get("/me")]
pub async fn me(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
) -> Result<Json<UserResponse>, Status> {
    let row = sqlx::query_as::<_, (String, String, String, String, String, bool, Option<chrono::NaiveDateTime>)>(
        "SELECT id, email, first_name, last_name, role, is_active, created_at FROM users WHERE id = ?"
    )
    .bind(&user.user_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match row {
        Some((id, email, first_name, last_name, role, is_active, created_at)) => {
            Ok(Json(UserResponse {
                id,
                email,
                first_name,
                last_name,
                role,
                is_active,
                created_at,
            }))
        }
        None => Err(Status::NotFound),
    }
}

#[post("/change-password", data = "<req>")]
pub async fn change_password(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
    req: Json<ChangePasswordRequest>,
) -> Result<Status, Status> {
    let row = sqlx::query_scalar::<_, String>(
        "SELECT password_hash FROM users WHERE id = ?"
    )
    .bind(&user.user_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match row {
        Some(current_hash) => {
            if !verify(&req.current_password, &current_hash).unwrap_or(false) {
                return Err(Status::Unauthorized);
            }

            let new_hash = hash(&req.new_password, DEFAULT_COST)
                .map_err(|_| Status::InternalServerError)?;

            sqlx::query("UPDATE users SET password_hash = ?, updated_at = NOW() WHERE id = ?")
                .bind(&new_hash)
                .bind(&user.user_id)
                .execute(pool.inner())
                .await
                .map_err(|_| Status::InternalServerError)?;

            Ok(Status::Ok)
        }
        None => Err(Status::NotFound),
    }
}
"}

