use crate::models::user::{UpdateUserRequest, UserResponse};
use crate::DbPool;
use rocket::http::Status;
use rocket::serde::json::Json;
use rocket::State;

#[get("/")]
pub async fn list_users(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
) -> Result<Json<Vec<UserResponse>>, Status> {
    if user.role != "administrator" && user.role != "academic_staff" {
        return Err(Status::Forbidden);
    }

    let rows = sqlx::query_as::<_, (String, String, String, String, String, bool, Option<chrono::NaiveDateTime>)>(
        "SELECT id, email, first_name, last_name, role, is_active, created_at FROM users ORDER BY created_at DESC"
    )
    .fetch_all(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    let users: Vec<UserResponse> = rows
        .into_iter()
        .map(|(id, email, first_name, last_name, role, is_active, created_at)| UserResponse {
            id,
            email,
            first_name,
            last_name,
            role,
            is_active,
            created_at,
        })
        .collect();

    Ok(Json(users))
}

#[get("/<user_id>")]
pub async fn get_user(
    pool: &State<DbPool>,
    auth: AuthenticatedUser,
    user_id: String,
) -> Result<Json<UserResponse>, Status> {
    // Users can view their own profile; admin/staff can view any
    if auth.user_id != user_id && auth.role != "administrator" && auth.role != "academic_staff" {
        return Err(Status::Forbidden);
    }

    let row = sqlx::query_as::<_, (String, String, String, String, String, bool, Option<chrono::NaiveDateTime>)>(
        "SELECT id, email, first_name, last_name, role, is_active, created_at FROM users WHERE id = ?"
    )
    .bind(&user_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match row {
        Some((id, email, first_name, last_name, role, is_active, created_at)) => {
            Ok(Json(UserResponse {
                id,
