    }

    let valid_types = ["journal_article", "conference_paper", "thesis", "book_chapter"];
    if !valid_types.contains(&req.submission_type.as_str()) {
        return Err(Status::BadRequest);
    }

    let id = Uuid::new_v4().to_string();

    sqlx::query(
        "INSERT INTO submissions (id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, 'draft', NOW(), NOW())"
    )
    .bind(&id)
    .bind(&user.user_id)
    .bind(&req.title)
    .bind(&req.abstract_text)
    .bind(&req.content)
    .bind(&req.submission_type)
    .execute(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    let sub = Submission {
        id,
        author_id: user.user_id,
        title: req.title.clone(),
        abstract_text: req.abstract_text.clone(),
        content: req.content.clone(),
        submission_type: req.submission_type.clone(),
        status: "draft".to_string(),
        submitted_at: None,
        updated_at: None,
    };

    Ok(Json(sub))
}

#[get("/")]
pub async fn list_submissions(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
) -> Result<Json<Vec<Submission>>, Status> {
    let query = match user.role.as_str() {
        "administrator" | "academic_staff" => {
            "SELECT id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at FROM submissions ORDER BY submitted_at DESC".to_string()
        }
        "instructor" => {
            // Instructors see all submitted/in-review plus their own
            format!(
                "SELECT id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at FROM submissions WHERE author_id = '{}' OR status IN ('submitted', 'in_review', 'accepted', 'rejected') ORDER BY submitted_at DESC",
                user.user_id
            )
        }
        _ => {
            // Students see only their own
            format!(
                "SELECT id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at FROM submissions WHERE author_id = '{}' ORDER BY submitted_at DESC",
                user.user_id
            )
        }
    };

    let rows = sqlx::query_as::<_, (String, String, String, String, String, String, String, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
        &query
    )
    .fetch_all(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    let subs: Vec<Submission> = rows
        .into_iter()
        .map(|(id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at)| Submission {
            id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at,
        })
        .collect();

    Ok(Json(subs))
}

