        "SELECT id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at FROM submissions WHERE id = ?"
    )
    .bind(&submission_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match row {
        Some((id, author_id, title, abstract_text, content, submission_type, status, submitted_at, updated_at)) => {
            Ok(Json(Submission {
