    pool: &State<DbPool>,
    user: AuthenticatedUser,
    submission_id: String,
    req: Json<UpdateSubmissionRequest>,
) -> Result<Json<Submission>, Status> {
    // Check ownership or admin rights
    let owner = sqlx::query_scalar::<_, String>(
        "SELECT author_id FROM submissions WHERE id = ?"
    )
    .bind(&submission_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match owner {
        Some(author_id) => {
            let is_admin = user.role == "administrator" || user.role == "academic_staff";
            if author_id != user.user_id && !is_admin {
                return Err(Status::Forbidden);
            }

            // Only admin/staff can change status
            if req.status.is_some() && !is_admin {
                return Err(Status::Forbidden);
            }
        }
        None => return Err(Status::NotFound),
    }

    if let Some(ref title) = req.title {
        sqlx::query("UPDATE submissions SET title = ?, updated_at = NOW() WHERE id = ?")
            .bind(title)
            .bind(&submission_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }
    if let Some(ref abstract_text) = req.abstract_text {
        sqlx::query("UPDATE submissions SET abstract_text = ?, updated_at = NOW() WHERE id = ?")
            .bind(abstract_text)
            .bind(&submission_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }
    if let Some(ref content) = req.content {
        sqlx::query("UPDATE submissions SET content = ?, updated_at = NOW() WHERE id = ?")
            .bind(content)
            .bind(&submission_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }
    if let Some(ref status) = req.status {
        sqlx::query("UPDATE submissions SET status = ?, updated_at = NOW() WHERE id = ?")
            .bind(status)
            .bind(&submission_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }

    get_submission(pool, _user, submission_id).await
}

#[delete("/<submission_id>")]
pub async fn delete_submission(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
    submission_id: String,
) -> Result<Status, Status> {
    let owner = sqlx::query_scalar::<_, String>(
        "SELECT author_id FROM submissions WHERE id = ?"
    )
    .bind(&submission_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match owner {
        Some(author_id) => {
            if author_id != user.user_id && user.role != "administrator" {
                return Err(Status::Forbidden);
            }
        }
        None => return Err(Status::NotFound),
    }

    sqlx::query("DELETE FROM submissions WHERE id = ?")
        .bind(&submission_id)
        .execute(pool.inner())
        .await
        .map_err(|_| Status::InternalServerError)?;

    Ok(Status::NoContent)
}

