#[post("/", data = "<req>")]
pub async fn create_review(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
    req: Json<CreateReviewRequest>,
) -> Result<Json<Review>, Status> {
    if user.role != "instructor" && user.role != "academic_staff" {
        return Err(Status::Forbidden);
    }

    if req.rating < 1 || req.rating > 10 {
        return Err(Status::BadRequest);
    }

    let valid_recommendations = ["accept", "minor_revision", "major_revision", "reject"];
    if !valid_recommendations.contains(&req.recommendation.as_str()) {
        return Err(Status::BadRequest);
    }

    let id = Uuid::new_v4().to_string();

    sqlx::query(
        "INSERT INTO reviews (id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, 'pending', NOW(), NOW())"
    )
    .bind(&id)
    .bind(&req.submission_id)
    .bind(&user.user_id)
    .bind(req.rating)
    .bind(&req.comments)
    .bind(&req.recommendation)
    .execute(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    Ok(Json(Review {
        id,
        submission_id: req.submission_id.clone(),
        reviewer_id: user.user_id,
        rating: req.rating,
        comments: req.comments.clone(),
        recommendation: req.recommendation.clone(),
        status: "pending".to_string(),
        created_at: None,
        updated_at: None,
    }))
}

#[get("/")]
pub async fn list_reviews(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
) -> Result<Json<Vec<Review>>, Status> {
    let query = match user.role.as_str() {
        "administrator" | "academic_staff" => {
            "SELECT id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at FROM reviews ORDER BY created_at DESC".to_string()
        }
        "instructor" => {
            format!(
                "SELECT id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at FROM reviews WHERE reviewer_id = '{}' ORDER BY created_at DESC",
                user.user_id
            )
        }
        _ => return Err(Status::Forbidden),
    };

    let rows = sqlx::query_as::<_, (String, String, String, i32, String, String, String, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
        &query
    )
    .fetch_all(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    let reviews: Vec<Review> = rows
        .into_iter()
        .map(|(id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at)| Review {
            id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at,
        })
        .collect();

    Ok(Json(reviews))
}

#[get("/<review_id>")]
pub async fn get_review(
    pool: &State<DbPool>,
    _user: AuthenticatedUser,
    review_id: String,
) -> Result<Json<Review>, Status> {
    let row = sqlx::query_as::<_, (String, String, String, i32, String, String, String, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
        "SELECT id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at FROM reviews WHERE id = ?"
    )
    .bind(&review_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match row {
        Some((id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at)) => {
            Ok(Json(Review {
                id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at,
            }))
        }
        None => Err(Status::NotFound),
    }
}

#[put("/<review_id>", data = "<req>")]
pub async fn update_review(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
    review_id: String,
    req: Json<UpdateReviewRequest>,
) -> Result<Json<Review>, Status> {
    let owner = sqlx::query_scalar::<_, String>(
        "SELECT reviewer_id FROM reviews WHERE id = ?"
    )
    .bind(&review_id)
    .fetch_optional(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    match owner {
        Some(reviewer_id) => {
            if reviewer_id != user.user_id && user.role != "administrator" {
                return Err(Status::Forbidden);
            }
        }
        None => return Err(Status::NotFound),
    }

    if let Some(rating) = req.rating {
        sqlx::query("UPDATE reviews SET rating = ?, updated_at = NOW() WHERE id = ?")
            .bind(rating)
            .bind(&review_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }
    if let Some(ref comments) = req.comments {
        sqlx::query("UPDATE reviews SET comments = ?, updated_at = NOW() WHERE id = ?")
            .bind(comments)
            .bind(&review_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }
    if let Some(ref recommendation) = req.recommendation {
        sqlx::query("UPDATE reviews SET recommendation = ?, updated_at = NOW() WHERE id = ?")
            .bind(recommendation)
            .bind(&review_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }
    if let Some(ref status) = req.status {
        sqlx::query("UPDATE reviews SET status = ?, updated_at = NOW() WHERE id = ?")
            .bind(status)
            .bind(&review_id)
            .execute(pool.inner())
            .await
            .map_err(|_| Status::InternalServerError)?;
    }

    get_review(pool, user, review_id).await
}

#[post("/assign", data = "<req>")]
pub async fn assign_reviewer(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
    req: Json<AssignReviewerRequest>,
) -> Result<Status, Status> {
    if user.role != "administrator" && user.role != "academic_staff" {
        return Err(Status::Forbidden);
    }

    // Update submission status to in_review
    sqlx::query("UPDATE submissions SET status = 'in_review', updated_at = NOW() WHERE id = ?")
        .bind(&req.submission_id)
        .execute(pool.inner())
        .await
        .map_err(|_| Status::InternalServerError)?;

    // Create a pending review assignment
    let id = Uuid::new_v4().to_string();
    sqlx::query(
        "INSERT INTO reviews (id, submission_id, reviewer_id, rating, comments, recommendation, status, created_at, updated_at) VALUES (?, ?, ?, 0, '', '', 'assigned', NOW(), NOW())"
    )
    .bind(&id)
    .bind(&req.submission_id)
    .bind(&req.reviewer_id)
    .execute(pool.inner())
    .await
    .map_err(|_| Status::InternalServerError)?;

    Ok(Status::Created)
}

