#[get("/dashboard")]
pub async fn dashboard_stats(
    pool: &State<DbPool>,
    user: AuthenticatedUser,
) -> Result<Json<serde_json::Value>, Status> {
    if user.role != "administrator" {
        return Err(Status::Forbidden);
    }

    let user_count = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM users")
        .fetch_one(pool.inner())
        .await
        .unwrap_or(0);

    let submission_count = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM submissions")
        .fetch_one(pool.inner())
        .await
        .unwrap_or(0);

    let order_count = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM orders")
        .fetch_one(pool.inner())
        .await
        .unwrap_or(0);

    let pending_reviews = sqlx::query_scalar::<_, i64>(
        "SELECT COUNT(*) FROM reviews WHERE status IN ('pending', 'assigned')",
    )
    .fetch_one(pool.inner())
    .await
    .unwrap_or(0);

    let open_cases = sqlx::query_scalar::<_, i64>(
        "SELECT COUNT(*) FROM cases WHERE status = 'open'",
    )
    .fetch_one(pool.inner())
    .await
    .unwrap_or(0);

