{"file_path": "/home/eren/Documents/task4/Meridian_Academy/repo/frontend/src/services/api.rs", "content": "use gloo_net::http::Request;
use gloo_storage::{LocalStorage, Storage};
use serde::{de::DeserializeOwned, Serialize};

const BACKEND_URL: &str = "http://localhost:8000";

pub async fn get<T: DeserializeOwned>(path: &str) -> Result<T, String> {
    let url = format!("{}{}", BACKEND_URL, path);
    let mut req = Request::get(&url);

    if let Ok(token) = LocalStorage::get::<String>("auth_token") {
        req = req.header("Authorization", &format!("Bearer {}", token));
    }

    let resp = req.send().await.map_err(|e| e.to_string())?;

    if resp.ok() {
        resp.json::<T>().await.map_err(|e| e.to_string())
    } else {
        Err(format!("Request failed with status: {}", resp.status()))
    }
}

pub async fn post<T: DeserializeOwned, B: Serialize>(path: &str, body: &B) -> Result<T, String> {
    let url = format!("{}{}", BACKEND_URL, path);
    let mut req = Request::post(&url).json(body).map_err(|e| e.to_string())?;

    if let Ok(token) = LocalStorage::get::<String>("auth_token") {
        req = req.header("Authorization", &format!("Bearer {}", token));
    }

    let resp = req.send().await.map_err(|e| e.to_string())?;

    if resp.ok() {
        resp.json::<T>().await.map_err(|e| e.to_string())
    } else {
        Err(format!("Request failed with status: {}", resp.status()))
    }
}

pub async fn put<T: DeserializeOwned, B: Serialize>(path: &str, body: &B) -> Result<T, String> {
    let url = format!("{}{}", BACKEND_URL, path);
    let mut req = Request::put(&url).json(body).map_err(|e| e.to_string())?;

    if let Ok(token) = LocalStorage::get::<String>("auth_token") {
        req = req.header("Authorization", &format!("Bearer {}", token));
    }

    let resp = req.send().await.map_err(|e| e.to_string())?;

    if resp.ok() {
        resp.json::<T>().await.map_err(|e| e.to_string())
    } else {
        Err(format!("Request failed with status: {}", resp.status()))
    }
}

pub async fn delete(path: &str) -> Result<(), String> {
    let url = format!("{}{}", BACKEND_URL, path);
    let mut req = Request::delete(&url);

    if let Ok(token) = LocalStorage::get::<String>("auth_token") {
        req = req.header("Authorization", &format!("Bearer {}", token));
    }

    let resp = req.send().await.map_err(|e| e.to_string())?;

    if resp.ok() {
        Ok(())
    } else {
        Err(format!("Request failed with status: {}", resp.status()))
    }
}
"}

