{"file_path": "/home/eren/Documents/task4/Meridian_Academy/repo/frontend/src/pages/submissions.rs", "content": "use dioxus::prelude::*;
use serde::{Deserialize, Serialize};
use crate::services::api;
use crate::Route;

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Submission {
    id: String,
    author_id: String,
    title: String,
    abstract_text: String,
    content: String,
    submission_type: String,
    status: String,
}

#[derive(Serialize)]
struct CreateSubmission {
    title: String,
    abstract_text: String,
    content: String,
    submission_type: String,
}

#[component]
pub fn SubmissionsPage() -> Element {
    let submissions = use_resource(|| async {
        api::get::<Vec<Submission>>("/api/submissions/my").await.unwrap_or_default()
    });

    rsx! {
        div { class: "page-container",
            div { class: "page-header",
                h2 { "My Submissions" }
                Link { to: Route::NewSubmission {}, class: "btn btn-primary", "New Submission" }
            }
            match &*submissions.read() {
                Some(subs) => rsx! {
                    div { class: "table-container",
                        table { class: "data-table",
                            thead {
                                tr {
                                    th { "Title" }
                                    th { "Type" }
                                    th { "Status" }
                                    th { "Actions" }
                                }
                            }
                            tbody {
                                for sub in subs.iter() {
                                    tr { key: "{sub.id}",
                                        td { "{sub.title}" }
                                        td { "{sub.submission_type}" }
                                        td {
                                            span { class: "status-badge status-{sub.status}", "{sub.status}" }
                                        }
                                        td {
                                            button { class: "btn btn-small", "View" }
                                        }
                                    }
                                }
                            }
                        }
                    }
                },
                None => rsx! { p { "Loading submissions..." } }
            }
        }
    }
}

#[component]
pub fn NewSubmissionPage() -> Element {
    let mut title = use_signal(String::new);
    let mut abstract_text = use_signal(String::new);
    let mut content = use_signal(String::new);
    let mut submission_type = use_signal(|| "journal_article".to_string());
    let mut message = use_signal(|| Option::<String>::None);
    let nav = use_navigator();

    let onsubmit = move |_| {
        let nav = nav.clone();
        let data = CreateSubmission {
            title: title.read().clone(),
            abstract_text: abstract_text.read().clone(),
            content: content.read().clone(),
            submission_type: submission_type.read().clone(),
        };
        spawn(async move {
            match api::post::<Submission, _>("/api/submissions", &data).await {
                Ok(_) => nav.push(Route::Submissions {}),
                Err(e) => message.set(Some(e)),
            }
        });
    };

    rsx! {
        div { class: "page-container",
            h2 { "New Submission" }
            if let Some(msg) = message.read().as_ref() {
                div { class: "error-message", "{msg}" }
            }
            form { onsubmit,
                div { class: "form-group",
                    label { "Title" }
                    input {
                        r#type: "text",
                        value: "{title}",
                        oninput: move |e| title.set(e.value()),
                        required: true
                    }
                }
                div { class: "form-group",
                    label { "Type" }
                    select {
                        value: "{submission_type}",
                        onchange: move |e| submission_type.set(e.value()),
                        option { value: "journal_article", "Journal Article" }
                        option { value: "conference_paper", "Conference Paper" }
                        option { value: "thesis", "Thesis" }
                        option { value: "book_chapter", "Book Chapter" }
                    }
                }
                div { class: "form-group",
                    label { "Abstract" }
                    textarea {
                        value: "{abstract_text}",
                        oninput: move |e| abstract_text.set(e.value()),
                        rows: "4",
                        required: true
                    }
                }
                div { class: "form-group",
                    label { "Content" }
                    textarea {
                        value: "{content}",
                        oninput: move |e| content.set(e.value()),
                        rows: "12",
                        required: true
                    }
                }
                button { r#type: "submit", class: "btn btn-primary", "Submit" }
            }
        }
    }
}
"}

