                        p { "Total Users" }
                    }
                    div { class: "stat-card",
                        h3 { "{s.total_submissions}" }
                        p { "Submissions" }
                    }
                    div { class: "stat-card",
                        h3 { "{s.total_orders}" }
                        p { "Orders" }
                    }
                    div { class: "stat-card",
                        h3 { "{s.pending_reviews}" }
                        p { "Pending Reviews" }
                    }
                    div { class: "stat-card",
                        h3 { "{s.open_cases}" }
                        p { "Open Cases" }
                    }
                    div { class: "stat-card",
                        h3 { "${s.total_revenue:.2}" }
                        p { "Total Revenue" }
                    }
                }
                div { class: "admin-links",
                    Link { to: Route::AdminUsers {}, class: "btn", "Manage Users" }
                }
            } else {
                p { "Loading dashboard..." }
            }
        }
    }
}

#[component]
pub fn AdminUsersPage() -> Element {
    let users = use_resource(|| async {
        api::get::<Vec<UserInfo>>("/api/users").await.unwrap_or_default()
    });

    let users_read = users.read();

    rsx! {
        div { class: "page-container",
            h2 { "User Management" }
            if let Some(user_list) = users_read.as_ref() {
                div { class: "table-container",
                    table { class: "data-table",
                        thead {
                            tr {
                                th { "Name" }
                                th { "Email" }
                                th { "Role" }
                                th { "Status" }
                                th { "Actions" }
                            }
                        }
                        tbody {
                            for u in user_list.iter() {
                                tr { key: "{u.id}",
