        if item.quantity > models::HIGH_QUANTITY_THRESHOLD {
            has_high_qty = true;
        }

        let li_id = Uuid::new_v4().to_string();
        sqlx::query(
            "INSERT INTO order_line_items (id, order_id, publication_title, series_name, quantity, unit_price, line_total) VALUES (?, ?, ?, ?, ?, ?, ?)"
