    sqlx::query("UPDATE abnormal_order_flags SET is_cleared = true, cleared_by = ?, cleared_at = NOW() WHERE order_id = ?")
        .bind(&user.user_id).bind(&req.order_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;

    Ok(Status::Ok)
}

