        "SELECT id, order_id, reporter_id, assigned_to, case_type, subject, description, status, priority, submitted_at, first_response_at, first_response_due, resolution_target, resolved_at, closed_at, created_at, updated_at FROM after_sales_cases WHERE reporter_id = ? ORDER BY created_at DESC"
    )
    .bind(&user.user_id).fetch_all(pool.inner()).await.map_err(|_| Status::InternalServerError)?;

    let cases: Vec<CaseWithSla> = rows.into_iter().map(|(id, oid, rid, ato, ct, subj, desc, status, prio, sa, fra, frd, rt, ra, ca_closed, ca, ua)| {
        let case = AfterSalesCase { id, order_id: oid, reporter_id: rid, assigned_to: ato, case_type: ct, subject: subj, description: desc, status, priority: prio, submitted_at: sa, first_response_at: fra, first_response_due: frd, resolution_target: rt, resolved_at: ra, closed_at: ca_closed, created_at: ca, updated_at: ua };
        compute_sla(&case)
    }).collect();

