            format!("SELECT id, order_id, reporter_id, assigned_to, case_type, subject, description, status, priority, submitted_at, first_response_at, first_response_due, resolution_target, resolved_at, closed_at, created_at, updated_at FROM after_sales_cases WHERE reporter_id = '{}' ORDER BY created_at DESC", user.user_id)
