    };

    let rows = sqlx::query_as::<_, (String, String, String, Option<String>, String, String, String, String, String, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(&query)
        .fetch_all(pool.inner()).await.map_err(|_| Status::InternalServerError)?;

    let cases: Vec<CaseWithSla> = rows.into_iter().map(|(id, oid, rid, ato, ct, subj, desc, status, prio, sa, fra, frd, rt, ra, ca_closed, ca, ua)| {
