pub async fn get_case(pool: &State<DbPool>, user: AuthenticatedUser, case_id: String) -> Result<Json<CaseWithSla>, Status> {
    let row = sqlx::query_as::<_, (String, String, String, Option<String>, String, String, String, String, String, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
        "SELECT id, order_id, reporter_id, assigned_to, case_type, subject, description, status, priority, submitted_at, first_response_at, first_response_due, resolution_target, resolved_at, closed_at, created_at, updated_at FROM after_sales_cases WHERE id = ?"
    )
    .bind(&case_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;

    match row {
        Some((id, oid, rid, ato, ct, subj, desc, status, prio, sa, fra, frd, rt, ra, ca_closed, ca, ua)) => {
            let is_admin = user.role == "administrator" || user.role == "academic_staff";
            if rid != user.user_id && !is_admin { return Err(Status::Forbidden); }
            let case = AfterSalesCase { id, order_id: oid, reporter_id: rid, assigned_to: ato, case_type: ct, subject: subj, description: desc, status, priority: prio, submitted_at: sa, first_response_at: fra, first_response_due: frd, resolution_target: rt, resolved_at: ra, closed_at: ca_closed, created_at: ca, updated_at: ua };
            Ok(Json(compute_sla(&case)))
        }
