use jsonwebtoken::{decode, DecodingKey, Validation};
use rocket::http::Status;
use rocket::request::{FromRequest, Outcome, Request};

#[derive(Debug)]
pub struct AuthenticatedUser {
    pub user_id: String,
    pub username: String,
    pub role: String,
    pub session_id: String,
}

#[rocket::async_trait]
impl<'r> FromRequest<'r> for AuthenticatedUser {
    type Error = &'static str;

    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Self::Error> {
        let jwt_secret = std::env::var("JWT_SECRET")
            .unwrap_or_else(|_| "default_dev_secret_change_me".into());

        let auth_header = request.headers().get_one("Authorization");

        match auth_header {
            Some(header) if header.starts_with("Bearer ") => {
                let token = &header[7..];
                match decode::<Claims>(
                    token,
                    &DecodingKey::from_secret(jwt_secret.as_bytes()),
                    &Validation::default(),
                ) {
                    Ok(token_data) => {
                        let claims = token_data.claims;

                        // Check session validity (30-minute idle timeout)
                        // We update last_activity and check expiry at the DB level
                        if let Some(pool) = request.rocket().state::<crate::DbPool>() {
                            let session_check = sqlx::query_as::<_, (bool, chrono::NaiveDateTime)>(
                                "SELECT is_active, expires_at FROM sessions WHERE id = ? AND user_id = ?"
                            )
                            .bind(&claims.session_id)
                            .bind(&claims.sub)
                            .fetch_optional(pool)
                            .await;

                            match session_check {
                                Ok(Some((is_active, expires_at))) => {
                                    let now = chrono::Utc::now().naive_utc();
                                    if !is_active || now > expires_at {
                                        return Outcome::Error((Status::Unauthorized, "Session expired"));
                                    }
                                    // Refresh session: update last_activity and extend expiry
                                    let new_expiry = now + chrono::Duration::minutes(
                                        crate::models::SESSION_IDLE_TIMEOUT_MINUTES
                                    );
                                    let _ = sqlx::query(
                                        "UPDATE sessions SET last_activity = ?, expires_at = ? WHERE id = ?"
                                    )
                                    .bind(now)
                                    .bind(new_expiry)
                                    .bind(&claims.session_id)
                                    .execute(pool)
                                    .await;
                                }
                                Ok(None) => {
                                    return Outcome::Error((Status::Unauthorized, "Session not found"));
                                }
                                Err(_) => {
                                    // If DB check fails, allow request but log warning
                                    log::warn!("Session DB check failed for user {}", claims.sub);
                                }
                            }
                        }

                        Outcome::Success(AuthenticatedUser {
                            user_id: claims.sub,
                            username: claims.username,
                            role: claims.role,
                            session_id: claims.session_id,
                        })
                    }
                    Err(_) => Outcome::Error((Status::Unauthorized, "Invalid token")),
                }
            }
            _ => Outcome::Error((Status::Unauthorized, "Missing authorization header")),
        }
    }
}
"}

