mod tests {
    use bcrypt::{hash, verify, DEFAULT_COST};
    use chrono::{Duration, Utc};
    use jsonwebtoken::{decode, encode, DecodingKey, EncodingKey, Header, Validation};
    use serde::{Deserialize, Serialize};
    use sha2::{Digest, Sha256};
    use uuid::Uuid;

    // ===== MODELS =====

    #[derive(Debug, Clone, PartialEq)]
    enum UserRole {
        Student,
        Instructor,
        AcademicStaff,
        Administrator,
    }

    impl UserRole {
        fn as_str(&self) -> &'static str {
            match self {
                UserRole::Student => "student",
                UserRole::Instructor => "instructor",
                UserRole::AcademicStaff => "academic_staff",
                UserRole::Administrator => "administrator",
            }
        }

        fn from_str(s: &str) -> Option<Self> {
            match s {
                "student" => Some(UserRole::Student),
                "instructor" => Some(UserRole::Instructor),
                "academic_staff" => Some(UserRole::AcademicStaff),
                "administrator" => Some(UserRole::Administrator),
                _ => None,
            }
        }
    }

    #[derive(Debug, Serialize, Deserialize)]
    struct Claims {
        sub: String,
        username: String,
        role: String,
        exp: usize,
        iat: usize,
        session_id: String,
    }

    // ===== RBAC FUNCTIONS =====

    fn can_manage_users(role: &str) -> bool {
        matches!(role, "administrator" | "academic_staff")
    }

    fn can_create_submission(role: &str) -> bool {
        matches!(role, "student" | "instructor")
    }

    fn can_review_submissions(role: &str) -> bool {
        matches!(role, "instructor" | "academic_staff")
    }

    fn can_manage_orders(role: &str) -> bool {
        matches!(role, "administrator" | "academic_staff")
    }

    fn can_access_admin(role: &str) -> bool {
        role == "administrator"
    }

    fn can_manage_content(role: &str) -> bool {
        role == "administrator"
    }

    fn can_manage_payments(role: &str) -> bool {
        matches!(role, "administrator" | "academic_staff")
    }

    // ===== CONTENT GOVERNANCE =====

    #[derive(Debug, Clone)]
    struct SensitiveWord {
        word: String,
        action: String, // "replace" or "block"
        replacement: Option<String>,
    }

    struct ContentCheckResult {
        is_blocked: bool,
        blocked_words: Vec<String>,
        processed_text: String,
    }

    fn check_sensitive_words(text: &str, words: &[SensitiveWord]) -> ContentCheckResult {
        let mut blocked_words = Vec::new();
        let mut processed = text.to_string();
        let text_lower = text.to_lowercase();

        for sw in words {
            let word_lower = sw.word.to_lowercase();
            if text_lower.contains(&word_lower) {
                match sw.action.as_str() {
                    "block" => {
                        blocked_words.push(sw.word.clone());
                    }
                    "replace" => {
                        let replacement = sw.replacement.clone().unwrap_or_else(|| "***".to_string());
                        let mut result = String::new();
                        let mut remaining = processed.as_str();
                        while let Some(pos) = remaining.to_lowercase().find(&word_lower) {
                            result.push_str(&remaining[..pos]);
                            result.push_str(&replacement);
                            remaining = &remaining[pos + sw.word.len()..];
                        }
                        result.push_str(remaining);
                        processed = result;
                    }
                    _ => {}
                }
            }
        }

        ContentCheckResult {
            is_blocked: !blocked_words.is_empty(),
            blocked_words,
            processed_text: processed,
        }
    }

    fn validate_metadata(title: &str, summary: Option<&str>, tags: Option<&str>, keywords: Option<&str>) -> Result<(), String> {
        if title.len() > 120 {
            return Err("Title must be 120 characters or fewer".to_string());
        }
        if let Some(s) = summary {
            if s.len() > 500 {
                return Err("Summary must be 500 characters or fewer".to_string());
            }
        }
        if let Some(t) = tags {
            for tag in t.split(',') {
                if tag.trim().len() > 50 {
                    return Err("Individual tag must be 50 characters or fewer".to_string());
                }
            }
        }
        if let Some(k) = keywords {
            for kw in k.split(',') {
                if kw.trim().len() > 50 {
                    return Err("Individual keyword must be 50 characters or fewer".to_string());
                }
            }
        }
        Ok(())
    }

    fn generate_seo(title: &str, summary: Option<&str>) -> (String, String, String) {
        let meta_title = if title.len() > 120 { title[..120].to_string() } else { title.to_string() };
        let meta_description = match summary {
            Some(s) if s.len() > 155 => s[..155].to_string(),
            Some(s) => s.to_string(),
            None if title.len() > 155 => title[..155].to_string(),
            None => title.to_string(),
        };
        let slug_val = slug::slugify(title);
        (meta_title, meta_description, slug_val)
    }

    fn validate_file_type(filename: &str, magic_bytes: &[u8]) -> Result<String, String> {
        let ext = filename.rsplit('.').next().unwrap_or("").to_lowercase();
        let allowed = match ext.as_str() {
            "pdf" => magic_bytes.starts_with(b"%PDF"),
            "docx" => magic_bytes.starts_with(&[0x50, 0x4B, 0x03, 0x04]),
            "png" => magic_bytes.starts_with(&[0x89, 0x50, 0x4E, 0x47]),
            "jpg" | "jpeg" => magic_bytes.starts_with(&[0xFF, 0xD8, 0xFF]),
            _ => return Err(format!("File type '{}' not allowed", ext)),
        };
        if !allowed {
            return Err(format!("File signature does not match extension '{}'", ext));
        }
        Ok(ext)
    }

    fn valid_case_transition(from: &str, to: &str) -> bool {
        matches!(
            (from, to),
            ("submitted", "in_review")
                | ("in_review", "awaiting_evidence")
                | ("in_review", "arbitrated")
                | ("awaiting_evidence", "in_review")
                | ("awaiting_evidence", "arbitrated")
                | ("arbitrated", "approved")
                | ("arbitrated", "denied")
                | ("approved", "closed")
                | ("denied", "closed")
        )
    }

    const MAX_FILE_SIZE: u64 = 25 * 1024 * 1024;
    const MAX_REVIEW_IMAGE_SIZE: u64 = 5 * 1024 * 1024;
    const MAX_REVIEW_IMAGES: usize = 6;
    const FOLLOWUP_WINDOW_DAYS: i64 = 14;
    const SESSION_IDLE_TIMEOUT_MINUTES: i64 = 30;
    const MAX_SUBMISSION_VERSIONS: i32 = 10;
    const HIGH_QUANTITY_THRESHOLD: i32 = 50;
    const REFUND_COUNT_THRESHOLD: i64 = 3;
    const PASSWORD_RESET_EXPIRY_MINUTES: i64 = 60;
    const SOFT_DELETE_HOLD_DAYS: i64 = 30;

    // ===== AUTH & SESSION TESTS =====

    #[test]
    fn test_password_hash_and_verify() {
        let password = "SecureP@ssw0rd!";
        let hashed = hash(password, DEFAULT_COST).unwrap();
        assert!(verify(password, &hashed).unwrap());
    }

    #[test]
    fn test_password_wrong_verify() {
        let password = "SecureP@ssw0rd!";
        let hashed = hash(password, DEFAULT_COST).unwrap();
        assert!(!verify("WrongPassword", &hashed).unwrap());
    }

    #[test]
    fn test_password_hash_unique_salts() {
        let password = "SamePassword123";
        let hash1 = hash(password, DEFAULT_COST).unwrap();
        let hash2 = hash(password, DEFAULT_COST).unwrap();
        assert_ne!(hash1, hash2);
    }

    #[test]
    fn test_jwt_encode_decode_with_session() {
        let secret = "test_jwt_secret";
        let now = Utc::now().timestamp() as usize;
        let session_id = Uuid::new_v4().to_string();

        let claims = Claims {
            sub: "user-123".to_string(),
            username: "testuser".to_string(),
            role: "student".to_string(),
            iat: now,
            exp: now + 3600,
            session_id: session_id.clone(),
        };

        let token = encode(&Header::default(), &claims, &EncodingKey::from_secret(secret.as_bytes())).unwrap();
        let decoded = decode::<Claims>(&token, &DecodingKey::from_secret(secret.as_bytes()), &Validation::default()).unwrap();

        assert_eq!(decoded.claims.sub, "user-123");
        assert_eq!(decoded.claims.username, "testuser");
        assert_eq!(decoded.claims.session_id, session_id);
    }

    #[test]
    fn test_jwt_expired_token() {
        let secret = "test_secret";
        let now = Utc::now().timestamp() as usize;
        let claims = Claims {
            sub: "user-123".to_string(), username: "test".to_string(),
            role: "student".to_string(), iat: now - 7200, exp: now - 3600,
            session_id: "sess-1".to_string(),
        };
        let token = encode(&Header::default(), &claims, &EncodingKey::from_secret(secret.as_bytes())).unwrap();
        assert!(decode::<Claims>(&token, &DecodingKey::from_secret(secret.as_bytes()), &Validation::default()).is_err());
    }

    #[test]
    fn test_jwt_wrong_secret() {
        let now = Utc::now().timestamp() as usize;
        let claims = Claims {
            sub: "user-123".to_string(), username: "test".to_string(),
            role: "student".to_string(), iat: now, exp: now + 3600,
            session_id: "sess-1".to_string(),
        };
        let token = encode(&Header::default(), &claims, &EncodingKey::from_secret(b"correct")).unwrap();
        assert!(decode::<Claims>(&token, &DecodingKey::from_secret(b"wrong"), &Validation::default()).is_err());
    }

    #[test]
    fn test_session_idle_timeout_30_minutes() {
        assert_eq!(SESSION_IDLE_TIMEOUT_MINUTES, 30);
        let now = Utc::now().naive_utc();
        let expires = now + Duration::minutes(SESSION_IDLE_TIMEOUT_MINUTES);
        assert!(expires > now);
        let diff = (expires - now).num_minutes();
        assert_eq!(diff, 30);
    }

    #[test]
    fn test_session_expiry_check() {
        let now = Utc::now().naive_utc();
        let expired = now - Duration::minutes(1);
        let active = now + Duration::minutes(29);
        assert!(now > expired); // session is expired
        assert!(now < active);  // session is still active
    }

    #[test]
    fn test_password_reset_token_expiry() {
        assert_eq!(PASSWORD_RESET_EXPIRY_MINUTES, 60);
        let now = Utc::now().naive_utc();
        let expires = now + Duration::minutes(PASSWORD_RESET_EXPIRY_MINUTES);
        let diff = (expires - now).num_minutes();
        assert_eq!(diff, 60);
    }

    #[test]
    fn test_soft_delete_hold_period() {
        assert_eq!(SOFT_DELETE_HOLD_DAYS, 30);
        let now = Utc::now().naive_utc();
        let deletion = now + Duration::days(SOFT_DELETE_HOLD_DAYS);
        let diff = (deletion - now).num_days();
        assert_eq!(diff, 30);
    }

    // ===== RBAC TESTS =====

    #[test]
    fn test_role_roundtrip() {
        for role in [UserRole::Student, UserRole::Instructor, UserRole::AcademicStaff, UserRole::Administrator] {
            let s = role.as_str();
            assert_eq!(UserRole::from_str(s).unwrap(), role);
        }
    }

    #[test]
    fn test_role_from_str_invalid() {
        assert_eq!(UserRole::from_str("superadmin"), None);
        assert_eq!(UserRole::from_str(""), None);
        assert_eq!(UserRole::from_str("STUDENT"), None);
    }

    #[test]
    fn test_rbac_student() {
        let role = "student";
        assert!(!can_manage_users(role));
        assert!(can_create_submission(role));
        assert!(!can_review_submissions(role));
        assert!(!can_manage_orders(role));
        assert!(!can_access_admin(role));
        assert!(!can_manage_content(role));
        assert!(!can_manage_payments(role));
    }

    #[test]
    fn test_rbac_instructor() {
        let role = "instructor";
        assert!(!can_manage_users(role));
        assert!(can_create_submission(role));
        assert!(can_review_submissions(role));
        assert!(!can_manage_orders(role));
        assert!(!can_access_admin(role));
        assert!(!can_manage_content(role));
        assert!(!can_manage_payments(role));
    }

    #[test]
    fn test_rbac_academic_staff() {
        let role = "academic_staff";
        assert!(can_manage_users(role));
        assert!(!can_create_submission(role));
        assert!(can_review_submissions(role));
        assert!(can_manage_orders(role));
        assert!(!can_access_admin(role));
        assert!(!can_manage_content(role));
        assert!(can_manage_payments(role));
    }

    #[test]
    fn test_rbac_administrator() {
        let role = "administrator";
        assert!(can_manage_users(role));
        assert!(!can_create_submission(role));
        assert!(!can_review_submissions(role));
        assert!(can_manage_orders(role));
        assert!(can_access_admin(role));
        assert!(can_manage_content(role));
        assert!(can_manage_payments(role));
    }

    // ===== SUBMISSION VERSIONING TESTS =====

    #[test]
    fn test_max_submission_versions() {
        assert_eq!(MAX_SUBMISSION_VERSIONS, 10);
        for v in 0..MAX_SUBMISSION_VERSIONS {
            assert!(v < MAX_SUBMISSION_VERSIONS);
        }
        assert!(10 >= MAX_SUBMISSION_VERSIONS); // at limit, no more allowed
    }

    #[test]
    fn test_submission_deadline_enforcement() {
        let now = Utc::now().naive_utc();
        let past_deadline = now - Duration::hours(1);
        let future_deadline = now + Duration::days(7);
        assert!(now > past_deadline); // should reject
        assert!(now < future_deadline); // should allow
    }

    #[test]
    fn test_version_timestamp_format() {
        let dt = chrono::NaiveDate::from_ymd_opt(2026, 4, 2).unwrap()
            .and_hms_opt(14, 30, 0).unwrap();
        let formatted = dt.format("%m/%d/%Y, %I:%M:%S %p").to_string();
        assert_eq!(formatted, "04/02/2026, 02:30:00 PM");
    }

    // ===== FILE VALIDATION TESTS =====

    #[test]
    fn test_validate_pdf_file() {
        let magic = b"%PDF-1.4";
        assert!(validate_file_type("paper.pdf", magic).is_ok());
        assert_eq!(validate_file_type("paper.pdf", magic).unwrap(), "pdf");
