        assert!(validate_file_type("paper.docx", magic).is_ok());
    }

    #[test]
    fn test_validate_png_file() {
        let magic = &[0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A];
        assert!(validate_file_type("image.png", magic).is_ok());
    }

